+use std::time::Duration;
+
+use reqwest::{Client, RequestBuilder};
+use serde_json::json;
+use tracing::debug;
+
+use fcp_sdk::migration::{
+    AttemptOutcome, ConnectorRuntime, HttpRetryConfig, RetryLoop,
+};
+
+use crate::error::{CloudflareError, CloudflareResult};
+use crate::types::*;
+
+/// Cloudflare API client with retry support.
+pub struct CloudflareClient {
+    client: Client,
+    base_url: String,
+    auth: CloudflareAuth,
+    account_id: String,
+    retry_config: HttpRetryConfig,
+}
+
+impl std::fmt::Debug for CloudflareClient {
+    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
+        f.debug_struct("CloudflareClient")
+            .field("base_url", &self.base_url)
+            .field("auth", &self.auth)
+            .field("account_id", &self.account_id)
+            .finish()
+    }
+}
+
+impl CloudflareClient {
+    pub async fn new(
+        base_url: &str,
+        auth: CloudflareAuth,
+        account_id: &str,
+        retry_config: HttpRetryConfig,
+    ) -> CloudflareResult<Self> {
+        let client = Client::builder()
+            .timeout(Duration::from_secs(30))
+            .build()
+            .map_err(CloudflareError::Http)?;
+
+        Ok(Self {
+            client,
+            base_url: base_url.trim_end_matches('/').to_string(),
+            auth,
+            account_id: account_id.to_string(),
+            retry_config,
+        })
+    }
+
+    pub fn base_url(&self) -> &str {
+        &self.base_url
+    }
+
+    pub fn is_secretless(&self) -> bool {
+        match &self.auth {
+            CloudflareAuth::ApiToken { api_token } => api_token.is_empty(),
+            CloudflareAuth::ApiKey { api_key, .. } => api_key.is_empty(),
+        }
+    }
+
+    fn authenticate(&self, req: RequestBuilder) -> RequestBuilder {
+        match &self.auth {
+            CloudflareAuth::ApiToken { api_token } => {
+                if api_token.is_empty() {
+                    req // secretless mode
+                } else {
+                    req.bearer_auth(api_token)
+                }
+            }
+            CloudflareAuth::ApiKey { api_key, email } => {
+                if api_key.is_empty() {
+                    req
+                } else {
+                    req.header("X-Auth-Key", api_key.as_str())
+                        .header("X-Auth-Email", email.as_str())
+                }
+            }
+        }
+    }
+
+    // ── Health check ──
+
+    pub async fn health_check(
+        &self,
+        runtime: &ConnectorRuntime,
+    ) -> CloudflareResult<VerifyToken> {
+        let url = format!("{}/user/tokens/verify", self.base_url);
+        let ctx = runtime.request_context();
+        let policy = self.retry_config.to_retry_policy();
+
+        RetryLoop::execute(&ctx, &policy, |attempt| {
+            let url = url.clone();
+            let client = self.client.clone();
+            let auth = self.auth.clone();
+            async move {
+                debug!(attempt, "Verifying Cloudflare token");
+                let req = authenticate_request(client.get(&url), &auth);
+                handle_response::<VerifyToken>(req, attempt).await
+            }
+        })
+        .await
+    }
+
+    // ── Zones ──
+
+    pub async fn list_zones(
+        &self,
+        runtime: &ConnectorRuntime,
+    ) -> CloudflareResult<Vec<Zone>> {
+        let url = format!("{}/zones", self.base_url);
+        self.get_list(runtime, &url).await
+    }
+
+    // ── DNS ──
+
+    pub async fn list_dns_records(
+        &self,
