+        let Some(client) = &self.client else { return Ok(SelfCheckReport::degraded("not_configured", "Not configured")); };
+        let Some(runtime) = &self.runtime else { return Ok(SelfCheckReport::degraded("no_runtime", "No runtime")); };
+        match client.health_check(runtime).await {
+            Ok(v) if v.status == "active" => Ok(SelfCheckReport::ok()),
